mapper.select:
SELECT /* @SQLID=SUB0202_0106-02#Sql002 */ RTRIM(RTRIM(TRIM(TO_CHAR(NVL(A.DONE_OCO_SASHINE,'0'),'999,999,999,999,990.99')),'0'),'.') AS DONE_OCO_SASHINE, A.DONE_OCO_SASINARI_KBN AS DONE_OCO_SASINARI_KBN, A.DONE_RBE_ORDER_KIND AS DONE_RBE_ORDER_KIND, RTRIM(RTRIM(TRIM(TO_CHAR(NVL(A.DONE_TRIGGER_NEDAN,'0'),'999,999,999,999,990.99')),'0'),'.') AS DONE_TRIGGER_NEDAN, A.DONE_TRIGGER_ZONE AS DONE_TRIGGER_ZONE, RTRIM(RTRIM(TRIM(TO_CHAR(NVL(A.DONE_SASHINE,'0'),'999,999,999,999,990.99')),'0'),'.') AS DONE_SASHINE, A.DONE_SASINARI_KBN AS DONE_SASINARI_KBN, A.IFA_ORDER_SUB_NO AS IFA_ORDER_SUB_NO, A.IFA_ORDER_NO AS IFA_ORDER_NO, RTRIM(RTRIM(TRIM(TO_CHAR(NVL(A.OCO_SASHINE,'0'),'999,999,999,999,990.99')),'0'),'.') AS OCO_SASHINE, A.OCO_SASINARI_KBN AS OCO_SASINARI_KBN, A.RBE_ORDER_KIND AS RBE_ORDER_KIND, RTRIM(RTRIM(TRIM(TO_CHAR(NVL(A.TRIGGER_PRICE,'0'),'999,999,999,999,990.99')),'0'),'.') AS TRIGGER_PRICE, A.TRIGGER_ZONE AS TRIGGER_ZONE, A.DAILY_CREDIT_KBN AS DAILY_CREDIT_KBN, TO_CHAR(A.CREATE_TIME, 'YYYY/MM/DD HH24:MI:SS') AS CREATE_TIME, A.TRADE_KBN AS TRADE_KBN, A.MARKET AS MARKET, A.DATE_KBN AS DATE_KBN, A.PAYMENT_LIMIT AS PAYMENT_LIMIT, DECODE(TRIM(A.PAYMENT_LIMIT_DATE), '', A.PAYMENT_LIMIT_DATE, TO_NUMBER(TRIM(A.PAYMENT_LIMIT_DATE))) AS PAYMENT_LIMIT_DATE, RTRIM(RTRIM(TRIM(TO_CHAR(NVL(A.PRICE,'0'),'999,999,999,999,990.99')),'0'),'.') AS PRICE, A.SASINARI_KBN AS SASINARI_KBN, TRIM(TO_CHAR(A.QUANTITY,'999,999,999,999,990')) AS QUANTITY, A.ORDER_STATUS AS ORDER_STATUS, A.ORDER_SYUBETSU AS ORDER_SYUBETSU, A.SPECIFIC_KBN AS SPECIFIC_KBN, A.BRAND_CD AS BRAND_CD, A.AZUKARI_KBN AS AZUKARI_KBN, NVL(B.USER_NM, '-') AS USER_NM, RTRIM(RTRIM(TRIM(TO_CHAR(C.OPEN_PRICE/100,'9,999,999,999,990.99')),'0'),'.') AS OPEN_PRICE, TO_CHAR(TO_DATE(TRIM(C.OPEN_TRADE_DATE),'yyyymmdd'),'YYYY/MM/DD') AS OPEN_TRADE_DATE, C.OPEN_MARKET AS OPEN_MARKET FROM T_JP_ORDER A LEFT JOIN TB_MED_USERS B ON A.CREATE_USER = B.USER_ID LEFT JOIN J_ORDER_POSITION_LINK C ON A.IFA_ORDER_NO = C.IFA_ORDER_NO WHERE TO_CHAR(A.CREATE_TIME, 'YYYY/MM/DD') = #{req.recordDate} AND A.CREATE_USER = #{req.createUser}
AND A.TRADE_KBN IN
#{tradeKbn}
AND A.ORDER_STATUS = '0' AND A.CUSTOMER_ID = #{req.customerId} AND ((TRIM(A.SHUBETU) IS NULL AND A.SHUBETU IS NOT NULL) OR (TRIM(A.SHUBETU) = 'APL' AND A.CODE LIKE 'W%')) ORDER BY A.CREATE_TIME DESC FETCH FIRST 99 ROWS ONLY

SELECT /* @SQLID=SUB0202_0106-02#Sql003 */ A.IFA_ORDER_SUB_NO AS IFA_ORDER_SUB_NO, A.IFA_ORDER_NO AS IFA_ORDER_NO, TRIM(A.FUND_CD_GOU) AS FUND_CD_GOU, A.FUND_CD_KAISU AS FUND_CD_KAISU, A.NORIKAE_YUGU_KBN AS NORIKAE_YUGU_KBN, TO_CHAR(A.CREATE_TIME, 'YYYY/MM/DD HH24:MI:SS') AS CREATE_TIME, A.TRADE_TYPE AS TRADE_TYPE, TRIM(TO_CHAR(A.QUANTITY,'999,999,999,999,990')) AS QUANTITY, A.TRADE_KBN AS TRADE_KBN, A.SPECIFIC_KBN AS SPECIFIC_KBN, A.AZUKARI_KBN AS AZUKARI_KBN, TRIM(TO_CHAR(A.NET_AMOUNT,'999,999,999,999,990')) AS NET_AMOUNT, A.POINT_TYPE AS POINT_TYPE, TRIM(TO_CHAR(A.POINT,'999,999,999,999,990')) AS POINT, NVL(B.USER_NM, '-') AS USER_NM FROM JP_TOUSHIN_ORDER A LEFT JOIN TB_MED_USERS B ON A.CREATE_USER = B.USER_ID WHERE TO_CHAR(A.CREATE_TIME, 'YYYY/MM/DD') = #{req.recordDate} AND A.CREATE_USER = #{req.createUser}
AND TRIM(A.TRADE_TYPE) IN
#{tradeType}
AND A.ORDER_STATUS = '0' AND A.CUSTOMER_ID = #{req.customerId} AND ((TRIM(A.SHUBETU) IS NULL AND A.SHUBETU IS NOT NULL) OR (TRIM(A.SHUBETU) = 'APL' AND A.CODE LIKE 'W%')) ORDER BY A.CREATE_TIME DESC FETCH FIRST 99 ROWS ONLY
